# setup_default_parameters_template ----
## Setup ----
# No setup required.

## IO correctness ----
test_that("`setup_default_parameters_template()` works with correct inputs", {
  result <- FIMS:::setup_default_parameters_template(n_parameters = 3)

  #' @description Test that output is a `tbl_df` with expected rows.
  expect_s3_class(result, "tbl_df")
  expect_equal(nrow(result), 3)

  #' @description Test that output contains expected columns.
  expect_true(all(c(
    "module_name", "fleet", "module_type", "label",
    "age", "length", "time", "value", "estimation_type",
    "distribution_type", "distribution"
  ) %in% names(result)))
})

## Edge handling ----
test_that("`setup_default_parameters_template()` works with edge cases", {
  result <- FIMS:::setup_default_parameters_template(n_parameters = 0)

  #' @description Test that zero parameters creates an empty tibble with expected columns.
  expect_equal(nrow(result), 0)
  expect_true(all(c(
    "module_name", "fleet", "module_type", "label",
    "age", "length", "time", "value", "estimation_type",
    "distribution_type", "distribution"
  ) %in% names(result)))
})

